BEGIN;
CREATE TABLE IF NOT EXISTS owner_accounts(id BIGSERIAL PRIMARY KEY,contact_id BIGINT NOT NULL UNIQUE REFERENCES contacts(id) ON DELETE RESTRICT,status VARCHAR(20) NOT NULL DEFAULT 'invited',preferred_language VARCHAR(10) NOT NULL DEFAULT 'it',last_login_at TIMESTAMPTZ,created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),disabled_at TIMESTAMPTZ,CHECK(status IN('invited','active','disabled')));
CREATE TABLE IF NOT EXISTS owner_property_access(id BIGSERIAL PRIMARY KEY,owner_account_id BIGINT NOT NULL REFERENCES owner_accounts(id) ON DELETE CASCADE,property_id BIGINT NOT NULL REFERENCES properties(id) ON DELETE CASCADE,access_role VARCHAR(30) NOT NULL DEFAULT 'owner',access_status VARCHAR(20) NOT NULL DEFAULT 'active',is_primary BOOLEAN NOT NULL DEFAULT FALSE,valid_from TIMESTAMPTZ NOT NULL DEFAULT NOW(),valid_until TIMESTAMPTZ,created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),revoked_at TIMESTAMPTZ,UNIQUE(owner_account_id,property_id),CHECK(access_role IN('owner','co_owner','delegate','legal_representative')),CHECK(access_status IN('active','revoked','expired')),CHECK(valid_until IS NULL OR valid_until>=valid_from));
CREATE TABLE IF NOT EXISTS owner_access_tokens(id BIGSERIAL PRIMARY KEY,owner_account_id BIGINT NOT NULL REFERENCES owner_accounts(id) ON DELETE CASCADE,token_hash CHAR(64) NOT NULL UNIQUE,token_type VARCHAR(20) NOT NULL,expires_at TIMESTAMPTZ NOT NULL,used_at TIMESTAMPTZ,revoked_at TIMESTAMPTZ,created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),created_by VARCHAR(200),CHECK(token_type IN('invitation','login')),CHECK(expires_at>created_at));
CREATE TABLE IF NOT EXISTS owner_sessions(id BIGSERIAL PRIMARY KEY,owner_account_id BIGINT NOT NULL REFERENCES owner_accounts(id) ON DELETE CASCADE,session_token_hash CHAR(64) NOT NULL UNIQUE,created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),last_seen_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),expires_at TIMESTAMPTZ NOT NULL,revoked_at TIMESTAMPTZ,CHECK(expires_at>created_at));
CREATE TABLE IF NOT EXISTS owner_publications(id BIGSERIAL PRIMARY KEY,property_id BIGINT NOT NULL REFERENCES properties(id) ON DELETE CASCADE,publication_type VARCHAR(40) NOT NULL,title VARCHAR(200) NOT NULL,summary TEXT,body TEXT NOT NULL,status VARCHAR(20) NOT NULL DEFAULT 'draft',published_at TIMESTAMPTZ,published_by VARCHAR(200),version_number INTEGER NOT NULL DEFAULT 1,supersedes_publication_id BIGINT REFERENCES owner_publications(id) ON DELETE RESTRICT,superseded_by_publication_id BIGINT REFERENCES owner_publications(id) ON DELETE RESTRICT,created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),archived_at TIMESTAMPTZ,CHECK(status IN('draft','published','archived')),CHECK(publication_type IN('general_update','marketing_update','visit_update','feedback_summary','strategy_update','milestone')),CHECK(version_number>=1),CHECK(BTRIM(title)<>''),CHECK(BTRIM(body)<>''));
CREATE TABLE IF NOT EXISTS owner_publication_reads(id BIGSERIAL PRIMARY KEY,publication_id BIGINT NOT NULL REFERENCES owner_publications(id) ON DELETE CASCADE,owner_account_id BIGINT NOT NULL REFERENCES owner_accounts(id) ON DELETE CASCADE,first_viewed_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),last_viewed_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),view_count INTEGER NOT NULL DEFAULT 1,acknowledged_at TIMESTAMPTZ,UNIQUE(publication_id,owner_account_id),CHECK(view_count>=1));
CREATE TABLE IF NOT EXISTS owner_feedback(id BIGSERIAL PRIMARY KEY,owner_account_id BIGINT NOT NULL REFERENCES owner_accounts(id) ON DELETE CASCADE,property_id BIGINT NOT NULL REFERENCES properties(id) ON DELETE CASCADE,feedback_type VARCHAR(30) NOT NULL,subject VARCHAR(150) NOT NULL,message TEXT NOT NULL,status VARCHAR(20) NOT NULL DEFAULT 'new',submitted_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),handled_at TIMESTAMPTZ,handled_by VARCHAR(200),linked_activity_id BIGINT REFERENCES activities(id) ON DELETE SET NULL,created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),CHECK(feedback_type IN('contact_request','correction_request','general_message','strategy_feedback')),CHECK(status IN('new','in_review','handled','closed')),CHECK(char_length(message)<=5000));
CREATE TABLE IF NOT EXISTS owner_audit_log(id BIGSERIAL PRIMARY KEY,owner_account_id BIGINT REFERENCES owner_accounts(id) ON DELETE SET NULL,property_id BIGINT REFERENCES properties(id) ON DELETE SET NULL,action VARCHAR(80) NOT NULL,entity_type VARCHAR(80),entity_id VARCHAR(100),result VARCHAR(20) NOT NULL DEFAULT 'success',metadata JSONB NOT NULL DEFAULT '{}'::jsonb,created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE INDEX IF NOT EXISTS idx_owner_access_account ON owner_property_access(owner_account_id);CREATE INDEX IF NOT EXISTS idx_owner_access_property ON owner_property_access(property_id);CREATE INDEX IF NOT EXISTS idx_owner_tokens_hash ON owner_access_tokens(token_hash);CREATE INDEX IF NOT EXISTS idx_owner_sessions_hash ON owner_sessions(session_token_hash);CREATE INDEX IF NOT EXISTS idx_owner_publications_property_status ON owner_publications(property_id,status,published_at DESC);CREATE INDEX IF NOT EXISTS idx_owner_feedback_status ON owner_feedback(status,submitted_at DESC);CREATE INDEX IF NOT EXISTS idx_owner_audit_created ON owner_audit_log(created_at DESC);
COMMIT;
